mapper.select:
select, tar.expiration_time from def_application a left join def_tenant_application_rel tar on a.id = tar.application_id
and a.name like #{name, typeHandler=fullLike}
and a.is_visible = 1 and tar.tenant_id = #{tenantId}
order by a.sort_value asc

SELECT

from def_application a


        and a.name like #{name, typeHandler=fullLike}

    and
    a.is_visible = 1 and a.id not in (
    select application_id from def_tenant_application_rel tar
    where a.id = tar.application_id and tar.tenant_id = #{tenantId}
    )

ORDER BY a.sort_value asc
